package com.ansh.motoverse.service;
import com.ansh.motoverse.model.Vehicle; import com.ansh.motoverse.repository.VehicleRepository; import org.springframework.stereotype.Service; import java.util.List;
@Service public class VehicleService { private final VehicleRepository vehicleRepository; public VehicleService(VehicleRepository vehicleRepository){this.vehicleRepository=vehicleRepository;} public List<Vehicle> getAllVehicles(){return vehicleRepository.findAll();} public List<Vehicle> getAvailableVehicles(){return vehicleRepository.findByAvailableTrue();} public List<Vehicle> searchVehicles(String keyword){return vehicleRepository.findByNameContainingIgnoreCaseOrCategoryContainingIgnoreCaseOrLocationContainingIgnoreCase(keyword,keyword,keyword);} }
